#include <iostream>
using namespace std;
int a[1005][1005],b[1005][1005],n,m,dx[]={0,1},dy[]={1,0};
int main()
{
    cin>>n>>m;
    a[1][1]=1;
    b[1][1]=1;
    for(int i=0;i<m;i++)
    {
        int x,y;
        cin>>x>>y;
        a[x][y]=1;
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(a[i][j]==0)
            {
                b[i][j]=(b[i][j-1]+b[i-1][j])%100003;
            }
        }
    }
    cout<<b[n][n];
    return 0;
}
